// Kuratierter Kerndatensatz zur Sira des Propheten Muhammad ﷺ.
// Quellen: Sira von Ibn Hisham, ar-Rahiq al-Makhtum (al-Mubarakpuri), Sahih al-Bukhari,
// Sahih Muslim u. a. (jeweils am Knoten angegeben). Umstrittenes ist mit [Khilaf] /
// [Jumhur] gekennzeichnet. Jahresangaben n. Chr.; AH wo üblich.

export type Era = "vorislamisch" | "mekka" | "medina";

export type NodeKategorie =
  | "prophet" | "familie" | "ehefrau" | "kind" | "gefährte" | "ansar"
  | "später_konvertit" | "gegner" | "verbündeter" | "ereignis" | "korrektur";

export type EdgeTyp =
  | "familie" | "ehe" | "konvertierte_durch" | "tötete" | "rettete"
  | "kämpfte_in" | "gefallen_in" | "gegner_von" | "lehrte"
  | "freigelassen_von" | "teilnahme";

export interface SiraNode {
  id: string;
  name: string;
  arabisch?: string;
  kategorie: NodeKategorie;
  era: Era;
  daten?: string;
  jahr: number; // Ankerjahr für Zeitfilter und Layout
  zusammenfassung: string;
  quellen: string[];
  // Nähe zum Propheten ﷺ: 1 = engster Kreis, 2 = bekannte Gefährten, 3 = weitere erfasste
  nähe?: number;
  // Lebens-, Wirkungs- und Reiseorte (Gräber/Legenden gekennzeichnet)
  wirkungsort?: string;
  // Anzahl überlieferter Hadithe (klassische Zählung nach Baqi ibn Makhlad; variiert je Ausgabe)
  überliefert?: number;
}

export interface SiraEdge {
  id: string;
  von: string;
  nach: string;
  typ: EdgeTyp;
  notiz?: string;
  datum?: string;
}

