export const siraEdges: SiraEdge[] = E.map(([von, nach, typ, notiz, datum], i) => ({
  id: `e${i}`,
  von,
  nach,
  typ,
  notiz,
  datum,
}));

export const nodeById = new Map(siraNodes.map((n) => [n.id, n]));
